"use client";

import { Toggle as TogglePrimitive } from "@base-ui/react/toggle";
import * as stylex from "@stylexjs/stylex";
import {
	type BorderRadiusProp,
	borderRadiusStyles,
} from "@/utils/layouts.styles";
import type { PropsWithStylex } from "@/utils/stylex.utils";
import {
	togglePressedStyles,
	toggleSizeStyles,
	toggleStyles,
	toggleVariantStyles,
} from "./toggle.styles";

export type ToggleVariant = "default" | "outline";
export type ToggleSize = "default" | "sm" | "lg";

export interface ToggleProps extends PropsWithStylex<TogglePrimitive.Props> {
	variant?: ToggleVariant;
	size?: ToggleSize;
	style?: stylex.StyleXStyles;
	radius?: BorderRadiusProp;
}

export function Toggle({
	children,
	style,
	variant = "default",
	radius,
	size = "default",
	...props
}: ToggleProps) {
	const variantStyle = toggleVariantStyles[variant];
	const sizeStyle = toggleSizeStyles[size];
	console.log("radius", radius);
	return (
		<TogglePrimitive
			data-slot="toggle"
			{...props}
			render={(renderProps, toggleState) => {
				const pressedStyle = togglePressedStyles[variant];
				const renderStyles = stylex.props(
					toggleStyles.base,
					variantStyle,
					sizeStyle,
					radius && borderRadiusStyles[radius],
					toggleState.pressed && pressedStyle,
					style,
				);
				return (
					<button {...renderProps} {...renderStyles}>
						{children}
					</button>
				);
			}}
		/>
	);
}

import * as stylex from "@stylexjs/stylex";
import { theme } from "@/lib/theme/contract.stylex";
import {
	dataRuleQueries,
	fontSize,
	fontWeight,
	spacing,
} from "@/lib/theme/tokens.stylex";
export const toggleSizeStyles = stylex.create({
	sm: {
		height: spacing.large,
		minWidth: spacing.large,
		paddingLeft: spacing.small,
		paddingRight: spacing.small,
	},
	lg: {
		height: spacing.xlarge,
		paddingLeft: spacing.medium,
		paddingRight: spacing.medium,
	},
	default: {
		height: spacing.large,
		minWidth: 36,
		paddingLeft: spacing.small,
		paddingRight: spacing.small,
	},
});

export const toggleVariantStyles = stylex.create({
	default: {
		borderColor: "transparent",
		color: theme.contentPrimary,
		backgroundColor: theme.backgroundSubtle,
	},
	outline: {
		borderColor: {
			default: theme.border,
			[dataRuleQueries.dataPressed]: theme.borderStrong,
		},
		color: theme.contentPrimary,
		backgroundColor: theme.backgroundSubtle,
	},
});

export const togglePressedStyles = stylex.create({
	default: {
		backgroundColor: theme.contentAccent,
	},
	outline: {
		outlineWidth: "0px",
		backgroundColor: theme.surfaceOverlay,
	},
});
export const toggleStyles = stylex.create({
	base: {
		position: "relative",
		display: "inline-flex",
		flexShrink: 0,
		alignItems: "center",
		justifyContent: "center",
		gap: spacing.small,
		whiteSpace: "nowrap",
		borderStyle: "solid",
		borderWidth: 1,
		borderRadius: theme.borderRadius,
		fontWeight: fontWeight.medium,
		fontSize: fontSize.small,
		lineHeight: 1.4,
		cursor: "pointer",
		userSelect: "none",
		outline: "none",
		backgroundColor: "transparent",
		transition: "box-shadow 0.15s ease",
		":focus-visible": {
			boxShadow: `0 0 0 2px ${theme.focusRing}`,
		},
		":disabled": {
			pointerEvents: "none",
			opacity: 0.64,
		},
	},
	icon: {
		flexShrink: 0,
		width: spacing.medium,
		height: spacing.medium,
	},
});
